(14, 'footer_info_text', 'general', '<div class=\"d-md-flex d-lg-block\">\r\n    <div class=\"mb-5 mr-md-7 mr-lg-0\">\r\n        \r\n    </div>\r\n    <div class=\"ml-md-6 ml-lg-0\">\r\n        <div class=\"mb-4 d-none\">\r\n            <h4 class=\"h6 font-weight-bold mb-2 font-size-17 text-light\">Contact Info</h4>\r\n            <address class=\"pr-4\">\r\n                    <span class=\"mb-2 h6 font-weight-normal text-light\">\r\n                        Office Address - 1234, Dhaka, Bangladesh -1213\r\n                    </span>\r\n            </address>\r\n        </div>\r\n        <ul class=\"list-inline mb-0\">\r\n            <li class=\"list-inline-item mr-2\">\r\n                <a class=\"btn btn-icon btn-bg-transparent\" \r\n                    href=\"https://www.facebook.com/flytrust\">\r\n                    <span class=\"fa fa-facebook-f btn-icon__inner text-light\"></span>\r\n                </a>\r\n            </li>\r\n            <li class=\"list-inline-item mr-2\">\r\n                <a class=\"btn btn-icon btn-bg-transparent\" \r\n                    href=\"https://www.linkedin.com/company/flytrust\">\r\n                    <span class=\"fa fa-linkedin btn-icon__inner text-light\"></span>\r\n                </a>\r\n            </li>\r\n            <li class=\"list-inline-item mr-2\">\r\n                <a class=\"btn btn-icon btn-bg-transparent\" \r\n                    href=\"https://www.youtube.com/@flytrust\">\r\n                    <span class=\"fa fa-youtube-play  btn-icon__inner text-light\"></span>\r\n                </a>\r\n            </li>\r\n            <li class=\"list-inline-item mr-2\">\r\n                <a class=\"btn btn-icon btn-bg-transparent\" \r\n                    href=\"https://www.instagram.com/flytrust/\">\r\n                    <span class=\"fa fa-instagram btn-icon__inner text-light\"></span>\r\n                </a>\r\n            </li>\r\n            \r\n        </ul>\r\n    </div>\r\n</div>', NULL, 6, 6, NULL, NULL,