(47, 'user_content_email_forget_password', 'user', '<h1>Hello!</h1>\r\n<p>You are receiving this email because we received a password reset request for your account.</p>\r\n<p style=\"text-align: center;\">[button_reset_password]</p>\r\n<p>This password reset link expire in 60 minutes.</p>\r\n<p>If you did not request a password reset, no further action is required.</p>\r\n<p>Regards,</p>\r\n<p><span style=\"color: #e83e8c; font-family: SFMono-Regular, Menlo, Monaco, Consolas, \'Liberation Mono\', \'Courier New\', monospace; font-size: 12.25px; background-color: #f4f6f8;\">[email]</span></p>', NULL, 6, NULL, NULL, NULL, '2025-01-07 09:10:05'),
