(79, 'vendor_content_email_registered', 'vendor', '<h1 style=\"text-align: center;\">Welcome!</h1>\r\n<h3>Hello [first_name] [last_name]</h3>\r\n<p>Thank you for signing up with My Travel! We hope you enjoy your time with us.</p>\r\n<p>Regards,</p>\r\n<p>My Travel</p>', NULL, 6, NULL, NULL, NULL, '2024-12-11 06:55:21'),
